from flask import Flask, request
from prometheus_client import Counter, generate_latest, REGISTRY
import hashlib

app = Flask(__name__)

# Define a Counter metric with labels for user_id, session_id, and request_path
REQUEST_COUNTER = Counter(
    'http_requests_total',
    'Total HTTP Requests',
    ['user_id', 'session_id', 'request_path_hash']
)

def hash_request_path(request_path):
    # Hash the request path to prevent cardinality explosion
    return hashlib.sha256(request_path.encode('utf-8')).hexdigest()

@app.route('/metrics')
def metrics():
    return generate_latest(REGISTRY)

@app.before_request
def track_request():
    user_id = request.headers.get('X-User-ID', 'unknown')
    session_id = request.headers.get('X-Session-ID', 'unknown')
    request_path_hash = hash_request_path(request.path)
    
    REQUEST_COUNTER.labels(user_id=user_id, session_id=session_id, request_path_hash=request_path_hash).inc()

@app.route('/')
def index():
    return "Welcome to the application!"

@app.route('/example')
def example():
    return "This is an example endpoint."

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)